/*:
 * @plugindesc v1.40 (Req YEP_X_CoreUpdatesOpt.js) Utility functions and
 * compatibility helpers for the Core Updates Optimization plugin.
 * @author Yanfly Engine Plugins
 *
 * @help
 * ============================================================================
 * Introduction
 * ============================================================================
 *
 * This plugin requires the following:
 * - YEP_CoreEngine plugin installed
 * - YEP_X_CoreUpdatesOpt plugin installed
 * - Installing this plugin under YEP_X_CoreUpdatesOpt
 *
 * This plugin provides supplementary utility functions used internally by
 * YEP_X_CoreUpdatesOpt to ensure compatibility across different project
 * configurations.
 *
 * In most cases, you will not need to configure this plugin at all. Simply
 * install it beneath YEP_X_CoreUpdatesOpt in the Plugin Manager and leave
 * the default settings unless you experience specific compatibility issues.
 *
 * ============================================================================
 * End of Helpfile
 * ============================================================================
 *
 * @param ---Version Detection---
 * @default
 *
 * @param VersionCheckMode
 * @text Version Check Mode
 * @parent ---Version Detection---
 * @type select
 * @option Automatic
 * @value auto
 * @option Manual
 * @value manual
 * @option Disabled
 * @value off
 * @desc How version detection is handled at startup.
 * Automatic is recommended for most projects.
 * @default auto
 *
 * @param FallbackVersion
 * @text Fallback Version
 * @parent ---Version Detection---
 * @type string
 * @desc Version string to assume if detection fails.
 * Leave blank to use YEP_X_CoreUpdatesOpt's detected version.
 * @default
 *
 * @param ---Cache Utilities---
 * @default
 *
 * @param CacheValidationMode
 * @text Cache Validation Mode
 * @parent ---Cache Utilities---
 * @type select
 * @option Standard
 * @value standard
 * @option Strict
 * @value strict
 * @option Permissive
 * @value permissive
 * @desc How strictly the cache utility validates loaded assets.
 * Standard is recommended for most projects.
 * @default standard
 *
 * @param CacheRetryLimit
 * @text Cache Retry Limit
 * @parent ---Cache Utilities---
 * @type number
 * @min 0
 * @max 10
 * @desc Number of times the cache utility will retry a failed
 * asset load before giving up. 0 disables retries.
 * @default 3
 *
 * @param ---System Integrity---
 * @default
 *
 * @param IntegrityCheckOnBoot
 * @text Integrity Check on Boot
 * @parent ---System Integrity---
 * @type boolean
 * @on YES
 * @off NO
 * @desc Run system integrity checks during Scene_Boot?
 * Recommended to keep enabled.
 * @default true
 *
 * @param IntegrityCheckVerbose
 * @text Verbose Integrity Logging
 * @parent ---System Integrity---
 * @type boolean
 * @on YES
 * @off NO
 * @desc Log integrity check results to the console?
 * Disable for release builds.
 * @default false
 */

